  ('fire-eq-tech-moex-01915', 'fire-eq-tech', 'fire-eq-tech-moex-104-99dbadc8', 'sub-fire-eq-tech-04', NULL, 'single_choice', '住宅火災往往因延遲偵知、通報及避難造成住戶傷亡，設置住宅用火災警報器可及早偵知火災發生，以 利住戶採取滅火、避難及通報等應變作為，依住宅用火災警報器設置辦法之規定，住宅用火災警報器之 安裝方式，下列何者錯誤？', '["裝置於天花板者，警報器距離天花板60公分以內", "不得裝置於牆面", "距離出風口1.5公尺以上", "以裝置於居室中心為原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:22+00:00", "source_pdf_sha1": "d267b2422afc", "answer_pdf_sha1": "2564ebe1eb47", "source_family": "moex-gov-tw", "moex": {"exam_code": "104060", "c": "402", "s": "0709", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警報與避難系統消防安全設備概要", "year": "104", "exam_name": "104年專門驗船師引水人第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
